// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
// STRY0067125 - added to align with rules on Task
function onLoad() {
	// STRY0075857
	if(g_form.getValue('u_tasking_authority.u_external_flag') == 'true'){
			g_form.showFieldMsg("u_tasking_authority", getMessage('Tasker - The OU selected is an external Organizational Unit'), "info");
	}

	// template Instance
	g_form.setReadOnly('u_tasking_authority',false);
	if(g_form.getValue('u_tasking_authority.u_external_flag') == 'true'){
		g_form.setReadOnly('u_primary_office',false);
	} else if (g_form.getValue('parent_task') + '' != ''){
		g_form.setReadOnly('u_primary_office',true);
	} else {
		// STRY0071489 - If new setting for system property definie if Primary Office Must Match Internal Tasking Authority
		if(g_scratchpad.primary_office_must_match_Internal_tasking_authority != 'true'){
			g_form.setReadOnly('u_primary_office',false);
		} else{
			g_form.setReadOnly('u_primary_office',true);
		}
	}

	var UserPermissions  = new GlideAjax('ClientUserInfoScripts');
	UserPermissions.addParam('sysparm_name','CanUserAssignSelfOrOthersInTemplate');
	UserPermissions.addParam("OU", g_form.getValue('primary_assignee'));
	UserPermissions.addParam("UserId", g_user.userID);
	UserPermissions.addParam("Template", g_form.getValue('routing_template_ref'));

	// call script include to determine if this user is a tasking authority of the primary assignee OU.
	UserPermissions.getXML(f_returnCanUserAssignSelfOrOthersInTemplate);
}

function f_returnCanUserAssignSelfOrOthersInTemplate(response){
	if (g_form.getValue('active') == 'true' ){
		var answer = response.responseXML.documentElement.getAttribute("answer");
		// if the current user is a Tasking Authority in the OU, allow them to change the assigned members
		g_form.setDisplay('u_assigned_member',answer);
		g_form.setDisabled('u_assigned_member', !answer);
	}
	g_form.setDisplay('u_tasking_authority.u_external_flag',false);
}
